(()=>{const e=document.querySelectorAll(".contact-card, .contact-footnote");if(e.forEach(e=>e.classList.add("reveal-on-scroll")),!("IntersectionObserver"in window))return void e.forEach(e=>e.classList.add("is-visible"));const t=new IntersectionObserver(e=>{e.forEach((e,s)=>{e.isIntersecting&&(setTimeout(()=>e.target.classList.add("is-visible"),90*s),t.unobserve(e.target))})},{threshold:.12,rootMargin:"0px 0px -8% 0px"});e.forEach(e=>t.observe(e))})();